 10→/**
 11→ * A parser that expects to receive a string consisting of [length] digits, or, if [length] is `null`,
 12→ * a string consisting of any number of digits.
 13→ */
 14→internal sealed class NumberConsumer<in Receiver>(
 15→    /** The number of digits to consume. `null` means that the length is variable. */
 16→    open val length: Int?,
 17→    /** The human-readable name of the entity being parsed here. */
 18→    val whatThisExpects: String
 19→) {
 20→    /**
 21→     * Wholly consumes the substring of [input] between indices [start] (inclusive) and [end] (exclusive).
 22→     *
 23→     * If [length] is non-null, [end] must be equal to [start] + [length].
 24→     * In any case, the substring between [start] and [end] must consist of ASCII digits only.
 25→     * [consume] itself does not necessarily check the length of the input string,
 26→     * instead expecting to be given a valid one.
 27→     *
 28→     * Returns `null` on success and a `NumberConsumptionError` on failure.
 29→     */
 30→    abstract fun consume(storage: Receiver, input: CharSequence, start: Int, end: Int): NumberConsumptionError?
 31→}
 32→
 33→internal interface NumberConsumptionError {
 34→    fun errorMessage(): String
 35→    object ExpectedInt: NumberConsumptionError {
 36→        override fun errorMessage() = "expected an Int value"
 37→    }
 38→    class TooManyDigits(val maxDigits: Int): NumberConsumptionError {
 39→        override fun errorMessage() = "expected at most $maxDigits digits"
 40→    }
 41→    class TooFewDigits(val minDigits: Int): NumberConsumptionError {
 42→        override fun errorMessage() = "expected at least $minDigits digits"
 43→    }
 44→    class WrongConstant(val expected: String): NumberConsumptionError {
 45→        override fun errorMessage() = "expected '$expected'"
 46→    }
 47→    class Conflicting(val conflicting: Any): NumberConsumptionError {
 48→        override fun errorMessage() = "attempted to overwrite the existing value '$conflicting'"
 49→    }
 50→}
