 52→/**
 53→ * A parser that accepts an [Int] value in range from `0` to [Int.MAX_VALUE].
 54→ */
 55→internal class UnsignedIntConsumer<in Receiver>(
 56→    private val minLength: Int?,
 57→    private val maxLength: Int?,
 58→    private val setter: AssignableField<Receiver, Int>,
 59→    name: String,
 60→    private val multiplyByMinus1: Boolean = false,
 61→) : NumberConsumer<Receiver>(if (minLength == maxLength) minLength else null, name) {
 62→
 63→    init {
 64→        require(length == null || length in 1..9) { "Invalid length for field $whatThisExpects: $length" }
 65→    }
 66→
 67→    override fun consume(storage: Receiver, input: CharSequence, start: Int, end: Int): NumberConsumptionError? = when {
 68→        maxLength != null && end - start > maxLength -> NumberConsumptionError.TooManyDigits(maxLength)
 69→        minLength != null && end - start < minLength -> NumberConsumptionError.TooFewDigits(minLength)
 70→        else -> when (val result = input.parseAsciiIntOrNull(start = start, end = end)) {
 71→            null -> NumberConsumptionError.ExpectedInt
 72→            else -> setter.setWithoutReassigning(storage, if (multiplyByMinus1) -result else result)
 73→        }
 74→    }
 75→}
