 77→internal class ReducedIntConsumer<in Receiver>(
 78→    override val length: Int,
 79→    private val setter: AssignableField<Receiver, Int>,
 80→    name: String,
 81→    val base: Int,
 82→): NumberConsumer<Receiver>(length, name) {
 83→
 84→    private val modulo = POWERS_OF_TEN[length]
 85→    private val baseMod = base % modulo
 86→    private val baseFloor = base - baseMod
 87→
 88→    init {
 89→        require(length in 1..9) { "Invalid length for field $whatThisExpects: $length" }
 90→    }
 91→
 92→    override fun consume(storage: Receiver, input: CharSequence, start: Int, end: Int): NumberConsumptionError? {
 93→        val result = input.parseAsciiInt(start = start, end = end)
 94→        return setter.setWithoutReassigning(storage, if (result >= baseMod) {
 95→            baseFloor + result
 96→        } else {
 97→            baseFloor + modulo + result
 98→        })
 99→    }
100→}
