package kotlinx.datetime.test

import kotlinx.datetime.*
import kotlin.test.Test
import kotlin.test.assertEquals
import kotlin.test.assertFailsWith

class ParsingInconsistenciesTest {

    @Test
    fun localDateParseAndIsoFormatParseAgreeOnLongExtendedYear() {
        val s = "+00000000000002022-07-16"
        val expected = LocalDate(2022, 7, 16)
        assertEquals(expected, LocalDate.parse(s))
        assertEquals(expected, LocalDate.Formats.ISO.parse(s))
    }

    @Test
    fun localDateTimeParseAndIsoFormatParseAgreeOnLongExtendedYear() {
        val s = "+00000000000002022-07-16T13:45:30"
        val expected = LocalDateTime(2022, 7, 16, 13, 45, 30)
        assertEquals(expected, LocalDateTime.parse(s))
        assertEquals(expected, LocalDateTime.Formats.ISO.parse(s))
    }

    @Test
    fun dateTimePeriodDoesNotParseBareP() {
